// Two LEDs + Pushbutton Demo
// LED1 (Red)  -> D12 via 220Ω
// LED2 (Blue) -> D11 via 220Ω
// BTN1        -> D2  with 10kΩ pull-down

const int LED1_PIN  = 12;
const int LED2_PIN  = 11;
const int BTN_PIN   =  2;

void setup() {
  pinMode(LED1_PIN, OUTPUT);
  pinMode(LED2_PIN, OUTPUT);
  pinMode(BTN_PIN,  INPUT);   // pull-down resistor keeps this LOW when not pressed
  digitalWrite(LED1_PIN, LOW);
  digitalWrite(LED2_PIN, LOW);
}

void loop() {
  bool btnPressed = digitalRead(BTN_PIN) == HIGH;

  if (!btnPressed) {
    // Idle: blink LED1 slowly, LED2 off
    digitalWrite(LED1_PIN, HIGH);
    digitalWrite(LED2_PIN, LOW);
    delay(700);
    digitalWrite(LED1_PIN, LOW);
    delay(700);
  } else {
    // Button held: both LEDs on solid
    digitalWrite(LED1_PIN, HIGH);
    digitalWrite(LED2_PIN, HIGH);
    delay(50);   // small debounce dwell
  }
}

